/// Secure key manager that generates and stores encryption keys
/// in platform-specific secure storage (Keychain on iOS, Keystore on Android)
class SecureKeyManager {
  static const String _encryptionKeyAlias = 'app_encryption_key_v1';
  static const String _hmacKeyAlias = 'app_hmac_key_v1';
  static const int _keyLengthBytes = 32; // 256-bit keys

  final FlutterSecureStorage _secureStorage;

  SecureKeyManager({FlutterSecureStorage? secureStorage})
      : _secureStorage = secureStorage ??
            const FlutterSecureStorage(
              aOptions: AndroidOptions(encryptedSharedPreferences: true),
              iOptions: IOSOptions(
                accessibility: KeychainAccessibility.first_unlock_this_device,
              ),
            );

  /// Retrieves or generates the AES encryption key
  Future<Uint8List> getEncryptionKey() async {
    String? storedKey = await _secureStorage.read(key: _encryptionKeyAlias);
    if (storedKey != null) {
      return base64Decode(storedKey);
    }
    final key = encrypt.SecureRandom(_keyLengthBytes).bytes;
    await _secureStorage.write(
      key: _encryptionKeyAlias,
      value: base64Encode(key),
    );
    return key;
  }

  /// Retrieves or generates the HMAC key for integrity verification
  Future<Uint8List> getHmacKey() async {
    String? storedKey = await _secureStorage.read(key: _hmacKeyAlias);
    if (storedKey != null) {
      return base64Decode(storedKey);
    }
    final key = encrypt.SecureRandom(_keyLengthBytes).bytes;
    await _secureStorage.write(
      key: _hmacKeyAlias,
      value: base64Encode(key),
    );
    return key;
  }

  /// Destroys all stored keys (use during logout or account deletion)
  Future<void> destroyKeys() async {
    await _secureStorage.delete(key: _encryptionKeyAlias);
    await _secureStorage.delete(key: _hmacKeyAlias);
  }

  /// Rotates encryption key - caller must re-encrypt all data
  Future<Uint8List> rotateEncryptionKey() async {
    final newKey = encrypt.SecureRandom(_keyLengthBytes).bytes;
    await _secureStorage.write(
      key: _encryptionKeyAlias,
      value: base64Encode(newKey),
    );
    return newKey;
  }
}

